 38→func loginCmd() *ucli.Command {
 39→	return &ucli.Command{
 40→		Name:  "login",
 41→		Usage: "Authenticate with the Flotsam API",
 42→		Flags: []ucli.Flag{
 43→			&ucli.StringFlag{Name: "email", Aliases: []string{"e"}, Usage: "email address"},
 44→			&ucli.StringFlag{Name: "password", Aliases: []string{"p"}, Usage: "password (omit for interactive prompt)"},
 45→		},
 46→		Action: func(ctx context.Context, cmd *ucli.Command) error {
 47→			email := cmd.String("email")
 48→			password := cmd.String("password")
 49→
 50→			if email == "" {
 51→				fmt.Fprint(os.Stderr, "Email: ")
 52→				if _, err := fmt.Fscanln(os.Stdin, &email); err != nil {
 53→					return fmt.Errorf("cli: read email: %w", err)
 54→				}
 55→			}
 56→
 57→			if password == "" {
 58→				fmt.Fprint(os.Stderr, "Password: ")
 59→				passBytes, err := term.ReadPassword(int(os.Stdin.Fd()))
 60→				if err != nil {
 61→					return fmt.Errorf("cli: read password: %w", err)
 62→				}
 63→				fmt.Fprintln(os.Stderr)
 64→				password = string(passBytes)
 65→			}
 66→
 67→			cfg, err := flt.LoadConfig()
 68→			if err != nil {
 69→				return err
 70→			}
 71→
 72→			client := flt.NewClient(cfg.APIURL, "")
 73→			token, user, err := client.Login(ctx, email, password)
 74→			if err != nil {
 75→				return err
 76→			}
 77→
 78→			if err := flt.SetToken(token); err != nil {
 79→				return err
 80→			}
 81→
 82→			name := user.Email
 83→			if user.DisplayName != nil {
 84→				name = *user.DisplayName
 85→			}
 86→			fmt.Fprintf(os.Stderr, "Logged in as %s\n", name)
 87→			return nil
 88→		},
 89→	}
 90→}
