  1→package cli
  2→
  3→import (
  4→	"bytes"
  5→	"context"
  6→	"encoding/json"
  7→	"fmt"
  8→	"io"
  9→	"net/http"
 10→	"strings"
 11→)
 12→
 13→// Client is a GraphQL HTTP client for the Flotsam API.
 14→type Client struct {
 15→	httpClient *http.Client
 16→	apiURL     string
 17→	token      string
 18→}
 19→
 20→// NewClient creates a new GraphQL client.
 21→func NewClient(apiURL, token string) *Client {
 22→	return &Client{
 23→		httpClient: &http.Client{},
 24→		apiURL:     strings.TrimRight(apiURL, "/"),
 25→		token:      token,
 26→	}
 27→}
 28→
 29→// Item represents an item returned from the API.
 30→type Item struct {
 31→	ID          string   `json:"id"`
 32→	Type        string   `json:"type"`
 33→	Status      string   `json:"status"`
 34→	Sensitivity string   `json:"sensitivity"`
 35→	Title       *string  `json:"title"`
 36→	ContentText *string  `json:"contentText"`
 37→	ContentURL  *string  `json:"contentUrl"`
 38→	Tags        []string `json:"tags"`
 39→	Source      string   `json:"source"`
 40→	CreatedAt   string   `json:"createdAt"`
 41→	UpdatedAt   string   `json:"updatedAt"`
 42→}
 43→
 44→// SearchResult represents a paginated list of items.
 45→type SearchResult struct {
 46→	Items   []Item `json:"items"`
 47→	Total   int    `json:"total"`
 48→	HasMore bool   `json:"hasMore"`
 49→}
 50→
 51→// UserInfo represents basic user information.
 52→type UserInfo struct {
 53→	ID          string  `json:"id"`
 54→	Email       string  `json:"email"`
 55→	DisplayName *string `json:"displayName"`
 56→}
 57→
 58→// NoteInput holds parameters for creating a text note.
 59→type NoteInput struct {
 60→	Content     string   `json:"content"`
 61→	Title       *string  `json:"title,omitempty"`
 62→	Tags        []string `json:"tags,omitempty"`
 63→	Sensitivity *string  `json:"sensitivity,omitempty"`
 64→}
 65→
 66→// BookmarkInput holds parameters for creating a bookmark.
 67→type BookmarkInput struct {
 68→	URL         string   `json:"url"`
 69→	Title       *string  `json:"title,omitempty"`
 70→	Tags        []string `json:"tags,omitempty"`
 71→	Sensitivity *string  `json:"sensitivity,omitempty"`
 72→}
 73→
 74→// ListOpts holds parameters for listing items.
 75→type ListOpts struct {
 76→	Types  []string
 77→	Limit  int
 78→	Offset int
 79→	Sort   string
 80→}
 81→
 82→// graphqlRequest is the JSON body sent to the GraphQL endpoint.
 83→type graphqlRequest struct {
 84→	Query     string         `json:"query"`
 85→	Variables map[string]any `json:"variables,omitempty"`
 86→}
 87→
 88→// graphqlResponse is the JSON response from the GraphQL endpoint.
 89→type graphqlResponse struct {
 90→	Data   json.RawMessage `json:"data"`
 91→	Errors []graphqlError  `json:"errors"`
 92→}
 93→
 94→// graphqlError represents a GraphQL error.
 95→type graphqlError struct {
 96→	Message    string         `json:"message"`
 97→	Extensions map[string]any `json:"extensions,omitempty"`
 98→}
 99→
100→// Do sends a GraphQL request and decodes the response data into result.
101→func (c *Client) Do(ctx context.Context, query string, variables map[string]any, result any) error {
102→	body, err := json.Marshal(graphqlRequest{
103→		Query:     query,
104→		Variables: variables,
105→	})
106→	if err != nil {
107→		return fmt.Errorf("cli: marshal request: %w", err)
108→	}
109→
110→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.apiURL+"/graphql", bytes.NewReader(body))
111→	if err != nil {
112→		return fmt.Errorf("cli: create request: %w", err)
113→	}
114→	req.Header.Set("Content-Type", "application/json")
115→	if c.token != "" {
116→		req.Header.Set("Authorization", "Bearer "+c.token)
117→	}
118→
119→	resp, err := c.httpClient.Do(req)
120→	if err != nil {
121→		return fmt.Errorf("cli: send request: %w", err)
122→	}
123→	defer func() { _ = resp.Body.Close() }()
124→
125→	respBody, err := io.ReadAll(resp.Body)
126→	if err != nil {
127→		return fmt.Errorf("cli: read response: %w", err)
128→	}
129→
130→	if resp.StatusCode == http.StatusUnauthorized {
131→		return fmt.Errorf("cli: not authenticated (run 'flotsam login' first)")
132→	}
133→	if resp.StatusCode != http.StatusOK {
134→		return fmt.Errorf("cli: unexpected status %d: %s", resp.StatusCode, string(respBody))
135→	}
136→
137→	var gqlResp graphqlResponse
138→	if err := json.Unmarshal(respBody, &gqlResp); err != nil {
139→		return fmt.Errorf("cli: parse response: %w", err)
140→	}
141→
142→	if len(gqlResp.Errors) > 0 {
143→		// Check if any error is an auth error via extensions.code.
144→		for _, e := range gqlResp.Errors {
145→			if code, _ := e.Extensions["code"].(string); code == "UNAUTHENTICATED" {
146→				return fmt.Errorf("cli: not authenticated (run 'flotsam login' first)")
147→			}
148→		}
149→		messages := make([]string, len(gqlResp.Errors))
150→		for i, e := range gqlResp.Errors {
151→			messages[i] = e.Message
152→		}
153→		return fmt.Errorf("cli: %s", strings.Join(messages, "; "))
154→	}
155→
156→	if result != nil {
157→		if err := json.Unmarshal(gqlResp.Data, result); err != nil {
158→			return fmt.Errorf("cli: decode data: %w", err)
159→		}
160→	}
161→
162→	return nil
163→}
