165→// GraphQL query and mutation strings.
166→const (
167→	loginMutation = `mutation Login($input: LoginInput!) {
168→  login(input: $input) {
169→    token
170→    user { id email displayName }
171→  }
172→}`
173→
174→	captureNoteMutation = `mutation CaptureNote($input: NoteInput!) {
175→  captureNote(input: $input) {
176→    id type status sensitivity title tags source createdAt
177→  }
178→}`
179→
180→	captureBookmarkMutation = `mutation CaptureBookmark($input: BookmarkInput!) {
181→  captureBookmark(input: $input) {
182→    id type status sensitivity title contentUrl tags source createdAt
183→  }
184→}`
185→
186→	searchQuery = `query Search($query: String!, $filter: ItemFilter, $limit: Int) {
187→  search(query: $query, filter: $filter, limit: $limit) {
188→    items { id type status sensitivity title contentText contentUrl tags createdAt }
189→    total
190→    hasMore
191→  }
192→}`
193→
194→	listQuery = `query Items($filter: ItemFilter, $limit: Int, $offset: Int, $sort: ItemSort) {
195→  items(filter: $filter, limit: $limit, offset: $offset, sort: $sort) {
196→    items { id type status sensitivity title contentText contentUrl tags createdAt }
197→    total
198→    hasMore
199→  }
200→}`
201→)
