226→// CaptureNote creates a text note item.
227→func (c *Client) CaptureNote(ctx context.Context, input NoteInput) (*Item, error) {
228→	var resp struct {
229→		CaptureNote Item `json:"captureNote"`
230→	}
231→
232→	vars := map[string]any{
233→		"input": map[string]any{
234→			"content":     input.Content,
235→			"title":       input.Title,
236→			"tags":        input.Tags,
237→			"sensitivity": input.Sensitivity,
238→		},
239→	}
240→
241→	if err := c.Do(ctx, captureNoteMutation, vars, &resp); err != nil {
242→		return nil, err
243→	}
244→	return &resp.CaptureNote, nil
245→}
