247→// CaptureBookmark creates a bookmark item.
248→func (c *Client) CaptureBookmark(ctx context.Context, input BookmarkInput) (*Item, error) {
249→	var resp struct {
250→		CaptureBookmark Item `json:"captureBookmark"`
251→	}
252→
253→	vars := map[string]any{
254→		"input": map[string]any{
255→			"url":         input.URL,
256→			"title":       input.Title,
257→			"tags":        input.Tags,
258→			"sensitivity": input.Sensitivity,
259→		},
260→	}
261→
262→	if err := c.Do(ctx, captureBookmarkMutation, vars, &resp); err != nil {
263→		return nil, err
