/**
 * Strict GraphQL utilities — re-exports urql hooks with types that reject raw strings.
 *
 * Import useQuery/useMutation from here instead of 'urql'. Raw string queries
 * bypass gql.tada's compile-time schema validation.
 *
 * Usage:
 *   import { graphql } from 'gql.tada'
 *   import { useQuery, useMutation } from '@/lib/graphql'
 *
 *   const MyQuery = graphql(`query MyQuery { ... }`)
 *   const [result] = useQuery({ query: MyQuery })
 */

import {
  useQuery as _useQuery,
  useMutation as _useMutation,
  type UseQueryResponse,
  type UseMutationResponse,
  type AnyVariables,
  type OperationContext,
  type RequestPolicy,
} from 'urql'

interface ParsedDocument {
  readonly kind: string
  readonly definitions: readonly unknown[]
}

interface StrictQueryArgs<Variables extends AnyVariables = AnyVariables> {
  query: ParsedDocument
  variables?: Variables
  requestPolicy?: RequestPolicy
  context?: Partial<OperationContext>
  pause?: boolean
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useQuery<Data = any, Variables extends AnyVariables = AnyVariables>(
  args: StrictQueryArgs<Variables>,
): UseQueryResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useQuery(args as any)
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useMutation<Data = any, Variables extends AnyVariables = AnyVariables>(
  query: ParsedDocument,
): UseMutationResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useMutation(query as any)
}

import { create } from 'zustand'
import { urqlClient } from '@/lib/urqlClient'
import { MeQuery } from '@/lib/queries'

const TOKEN_KEY = 'flotsam_token'

export interface User {
  id: string
  email: string
  displayName: string | null
}

interface AuthState {
  token: string | null
  user: User | null
  loading: boolean

  initialize: () => Promise<void>
  setAuth: (token: string, user: User) => void
  logout: () => void
  getToken: () => string | null
}

export const useAuthStore = create<AuthState>()((set, get) => ({
  token: null,
  user: null,
  loading: true,

  initialize: async () => {
    const token = localStorage.getItem(TOKEN_KEY)
    if (!token) {
      set({ loading: false })
      return
    }

    set({ token })

    try {
      const result = await urqlClient.query(MeQuery, {}).toPromise()
      if (result.data?.me) {
        set({
          user: {
            id: result.data.me.id,
            email: result.data.me.email,
            displayName: result.data.me.displayName ?? null,
          },
          loading: false,
        })
      } else {
        // Token is invalid or expired
        get().logout()
        set({ loading: false })
      }
    } catch {
      // Network error or other failure — clear invalid session
      get().logout()
      set({ loading: false })
    }
  },

  setAuth: (token: string, user: User) => {
    localStorage.setItem(TOKEN_KEY, token)
    set({ token, user, loading: false })
  },

  logout: () => {
    localStorage.removeItem(TOKEN_KEY)
    set({ token: null, user: null })
  },

  getToken: () => {
    return get().token
  },
}))

