    chunksRef.current = []
    setAudioBlob(null)
    setDuration(0)
    setError(null)
    setStatus('idle')
  }, [clearTimer, releaseStream])

  useEffect(() => {
    return () => {
      clearTimer()
      releaseStream()
      if (recorderRef.current && recorderRef.current.state !== 'inactive') {
        recorderRef.current.stop()
      }
    }
  }, [clearTimer, releaseStream])

  return { status, audioBlob, duration, error, start, stop, pause, resume, reset }
}

