        }
      } else {
        setError('Failed to start recording')
      }
    }
  }, [clearTimer, releaseStream])

  const stop = useCallback(() => {
    if (recorderRef.current && recorderRef.current.state !== 'inactive') {
      recorderRef.current.stop()
    }
  }, [])

