import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import {
  Container,
  Title,
  Tabs,
  TextInput,
  Textarea,
  Button,
  Stack,
  TagsInput,
  Alert,
} from '@mantine/core'
import { BookmarkPlus, FileText } from 'lucide-react'
import { graphql } from 'gql.tada'
import { useMutation } from '@/lib/graphql'

const CaptureBookmarkMutation = graphql(`
  mutation CaptureBookmark($input: BookmarkInput!) {
    captureBookmark(input: $input) {
      id
      title
      type
    }
  }
`)

const CaptureNoteMutation = graphql(`
  mutation CaptureNote($input: NoteInput!) {
    captureNote(input: $input) {
      id
      title
      type
    }
  }
`)

function BookmarkTab() {
  const navigate = useNavigate()
  const [url, setUrl] = useState('')
  const [title, setTitle] = useState('')
  const [tags, setTags] = useState<string[]>([])
  const [error, setError] = useState<string | null>(null)
  const [, executeMutation] = useMutation(CaptureBookmarkMutation)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)

    const result = await executeMutation({
      input: { url, title: title || undefined, tags: tags.length > 0 ? tags : undefined },
    })
    if (result.error) {
      setError(result.error.graphQLErrors[0]?.message ?? 'Capture failed')
      return
    }

    navigate('/')
  }

  return (
    <form onSubmit={handleSubmit}>
      <Stack gap="md">
        {error && (
          <Alert color="red" variant="light">
            {error}
          </Alert>
        )}
        <TextInput
          label="URL"
          type="url"
          required
          placeholder="https://example.com/article"
          value={url}
          onChange={(e) => setUrl(e.currentTarget.value)}
        />
        <TextInput
          label="Title"
          placeholder="Optional — extracted automatically"
          value={title}
          onChange={(e) => setTitle(e.currentTarget.value)}
        />
        <TagsInput
          label="Tags"
          placeholder="Add tags..."
          value={tags}
          onChange={setTags}
        />
        <Button type="submit">Save Bookmark</Button>
      </Stack>
    </form>
  )
}

function NoteTab() {
  const navigate = useNavigate()
  const [title, setTitle] = useState('')
  const [content, setContent] = useState('')
  const [tags, setTags] = useState<string[]>([])
  const [error, setError] = useState<string | null>(null)
  const [, executeMutation] = useMutation(CaptureNoteMutation)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)

    const result = await executeMutation({
      input: { title: title || undefined, content, tags: tags.length > 0 ? tags : undefined },
    })
    if (result.error) {
      setError(result.error.graphQLErrors[0]?.message ?? 'Capture failed')
      return
    }

    navigate('/')
  }

  return (
    <form onSubmit={handleSubmit}>
      <Stack gap="md">
        {error && (
          <Alert color="red" variant="light">
            {error}
          </Alert>
        )}
        <TextInput
          label="Title"
          placeholder="Optional"
          value={title}
          onChange={(e) => setTitle(e.currentTarget.value)}
        />
        <Textarea
          label="Content"
          required
          placeholder="Write your note..."
          minRows={4}
          autosize
          value={content}
          onChange={(e) => setContent(e.currentTarget.value)}
        />
        <TagsInput
          label="Tags"
          placeholder="Add tags..."
          value={tags}
          onChange={setTags}
        />
        <Button type="submit">Save Note</Button>
      </Stack>
    </form>
  )
}

export function Capture() {
  return (
    <Container size="sm" py="xl">
      <Stack gap="lg">
        <Title order={2}>Capture</Title>

        <Tabs defaultValue="bookmark">
          <Tabs.List>
            <Tabs.Tab value="bookmark" leftSection={<BookmarkPlus size={16} />}>
              Bookmark
            </Tabs.Tab>
            <Tabs.Tab value="note" leftSection={<FileText size={16} />}>
              Note
            </Tabs.Tab>
          </Tabs.List>

          <Tabs.Panel value="bookmark" pt="md">
            <BookmarkTab />
          </Tabs.Panel>

          <Tabs.Panel value="note" pt="md">
            <NoteTab />
          </Tabs.Panel>
        </Tabs>
      </Stack>
    </Container>
  )
}

