import { useMemo, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import {
  ActionIcon,
  Alert,
  Box,
  Button,
  Container,
  Group,
  Stack,
  Tabs,
  TagsInput,
  Text,
  TextInput,
  Textarea,
  Title,
} from '@mantine/core'
import { BookmarkPlus, FileText, Mic, Square } from 'lucide-react'
import { graphql } from 'gql.tada'
import { useMutation } from '@/lib/graphql'
import { useAudioRecorder } from '@/hooks/useAudioRecorder'
import { uploadAudio } from '@/lib/upload'
import classes from './Capture.module.css'

const CaptureBookmarkMutation = graphql(`
  mutation CaptureBookmark($input: BookmarkInput!) {
    captureBookmark(input: $input) {
      id
      title
      type
    }
  }
`)

const CaptureNoteMutation = graphql(`
  mutation CaptureNote($input: NoteInput!) {
    captureNote(input: $input) {
      id
      title
      type
    }
  }
`)

const CaptureVoiceNoteMutation = graphql(`
  mutation CaptureVoiceNote($input: VoiceNoteInput!) {
    captureVoiceNote(input: $input) {
      id
      title
      type
    }
  }
`)

function BookmarkTab() {
  const navigate = useNavigate()
  const [url, setUrl] = useState('')
  const [title, setTitle] = useState('')
  const [tags, setTags] = useState<string[]>([])
  const [error, setError] = useState<string | null>(null)
