    expect(result.current.duration).toBe(3)
  })

  it('transitions to stopped and produces audioBlob on stop', async () => {
    const { result } = renderHook(() => useAudioRecorder())
    await act(async () => {
      await result.current.start()
    })

    act(() => {
      result.current.stop()
    })
    expect(result.current.status).toBe('stopped')
    expect(result.current.audioBlob).toBeInstanceOf(Blob)
  })

  it('supports pause and resume', async () => {
    const { result } = renderHook(() => useAudioRecorder())
    await act(async () => {
      await result.current.start()
    })

    act(() => {
      result.current.pause()
    })
    expect(result.current.status).toBe('paused')

    act(() => {
      result.current.resume()
    })
    expect(result.current.status).toBe('recording')
  })

  it('pauses duration timer on pause', async () => {
    const { result } = renderHook(() => useAudioRecorder())
    await act(async () => {
      await result.current.start()
    })

    act(() => {
      vi.advanceTimersByTime(2000)
    })
    expect(result.current.duration).toBe(2)

    act(() => {
      result.current.pause()
    })

    act(() => {
      vi.advanceTimersByTime(5000)
    })
    expect(result.current.duration).toBe(2)
  })

  it('resets to idle state', async () => {
    const { result } = renderHook(() => useAudioRecorder())
    await act(async () => {
      await result.current.start()
    })
    act(() => {
      result.current.stop()
    })
    expect(result.current.status).toBe('stopped')

    act(() => {
      result.current.reset()
    })
    expect(result.current.status).toBe('idle')
    expect(result.current.audioBlob).toBeNull()
    expect(result.current.duration).toBe(0)
  })

  it('sets error on permission denied', async () => {
    const denied = new DOMException('Permission denied', 'NotAllowedError')
    vi.mocked(navigator.mediaDevices.getUserMedia).mockRejectedValueOnce(denied)

    const { result } = renderHook(() => useAudioRecorder())
    await act(async () => {
      await result.current.start()
    })

    expect(result.current.status).toBe('idle')
    expect(result.current.error).toBe('Microphone permission denied')
  })

  it('sets error when no microphone found', async () => {
    const notFound = new DOMException('No mic', 'NotFoundError')
    vi.mocked(navigator.mediaDevices.getUserMedia).mockRejectedValueOnce(notFound)

    const { result } = renderHook(() => useAudioRecorder())
    await act(async () => {
      await result.current.start()
    })

    expect(result.current.error).toBe('No microphone found')
  })
})

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { uploadAudio } from './upload'

vi.mock('@/stores/authStore', () => ({
  useAuthStore: {
    getState: vi.fn(() => ({
      getToken: () => 'test-token-123',
    })),
  },
}))

beforeEach(() => {
  vi.stubGlobal('fetch', vi.fn())
})

afterEach(() => {
  vi.unstubAllGlobals()
})

describe('uploadAudio', () => {
  it('uploads audio and returns result', async () => {
    const response = { key: 'user/uploads/abc.webm', content_type: 'audio/webm', size: 1234 }
    vi.mocked(fetch).mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(response),
    } as Response)

    const blob = new Blob(['audio data'], { type: 'audio/webm' })
    const result = await uploadAudio(blob)

    expect(result).toEqual(response)
  })

  it('includes authorization header', async () => {
    vi.mocked(fetch).mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve({ key: 'k', content_type: 'ct', size: 0 }),
    } as Response)

    const blob = new Blob(['audio'], { type: 'audio/webm' })
    await uploadAudio(blob)

    expect(fetch).toHaveBeenCalledWith('/upload', {
      method: 'POST',
      headers: { Authorization: 'Bearer test-token-123' },
      body: expect.any(FormData),
    })
  })

  it('throws on non-ok response', async () => {
    vi.mocked(fetch).mockResolvedValueOnce({
      ok: false,
      status: 413,
      text: () => Promise.resolve('File too large'),
    } as Response)

    const blob = new Blob(['audio'], { type: 'audio/webm' })
    await expect(uploadAudio(blob)).rejects.toThrow('Upload failed (413): File too large')
  })

  it('throws when not authenticated', async () => {
    const { useAuthStore } = await import('@/stores/authStore')
    vi.mocked(useAuthStore.getState).mockReturnValueOnce({
      getToken: () => null,
    } as ReturnType<typeof useAuthStore.getState>)

    const blob = new Blob(['audio'], { type: 'audio/webm' })
    await expect(uploadAudio(blob)).rejects.toThrow('Not authenticated')
  })
})

