import { describe, it, expect } from 'vitest'
import { screen } from '@testing-library/react'
import { MemoryRouter } from 'react-router-dom'
import { MantineProvider } from '@mantine/core'
import { render } from '@testing-library/react'
import { Provider as UrqlProvider } from 'urql'
import { theme } from '@/theme'
import { Capture } from './Capture'
import { createMockClient } from '@/test/mocks'

function renderCapture() {
  const mockClient = createMockClient()
  return render(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    <UrqlProvider value={mockClient as any}>
      <MantineProvider theme={theme}>
        <MemoryRouter>
          <Capture />
        </MemoryRouter>
      </MantineProvider>
    </UrqlProvider>,
  )
}

describe('Capture', () => {
  it('renders the capture page', () => {
    renderCapture()
    expect(screen.getByText('Capture')).toBeInTheDocument()
  })

  it('renders bookmark and note tabs', () => {
    renderCapture()
    expect(screen.getByRole('tab', { name: /bookmark/i })).toBeInTheDocument()
    expect(screen.getByRole('tab', { name: /note/i })).toBeInTheDocument()
  })

  it('shows bookmark form by default', () => {
    renderCapture()
    expect(screen.getByText('URL')).toBeInTheDocument()
    expect(screen.getByPlaceholderText('https://example.com/article')).toBeInTheDocument()
  })
})

