import { useMemo, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import {
  ActionIcon,
  Alert,
  Box,
  Button,
  Container,
  Group,
  Stack,
  Tabs,
  TagsInput,
  Text,
  TextInput,
  Textarea,
  Title,
} from '@mantine/core'
import { BookmarkPlus, FileText, Mic, Square } from 'lucide-react'
import { graphql } from 'gql.tada'
import { useMutation } from '@/lib/graphql'
import { useAudioRecorder } from '@/hooks/useAudioRecorder'
import { uploadAudio } from '@/lib/upload'
import classes from './Capture.module.css'

const CaptureBookmarkMutation = graphql(`
  mutation CaptureBookmark($input: BookmarkInput!) {
    captureBookmark(input: $input) {
      id
      title
      type
    }
  }
`)

const CaptureNoteMutation = graphql(`
  mutation CaptureNote($input: NoteInput!) {
    captureNote(input: $input) {
      id
      title
      type
    }
  }
`)

const CaptureVoiceNoteMutation = graphql(`
  mutation CaptureVoiceNote($input: VoiceNoteInput!) {
    captureVoiceNote(input: $input) {
      id
      title
      type
    }
  }
`)

function BookmarkTab() {
  const navigate = useNavigate()
  const [url, setUrl] = useState('')
  const [title, setTitle] = useState('')
  const [tags, setTags] = useState<string[]>([])
  const [error, setError] = useState<string | null>(null)
  const [, executeMutation] = useMutation(CaptureBookmarkMutation)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)

    const result = await executeMutation({
      input: { url, title: title || undefined, tags: tags.length > 0 ? tags : undefined },
    })
    if (result.error) {
      setError(result.error.graphQLErrors[0]?.message ?? 'Capture failed')
      return
    }

    navigate('/')
  }

  return (
    <form onSubmit={handleSubmit}>
      <Stack gap="md">
        {error && (
          <Alert color="red" variant="light">
            {error}
          </Alert>
        )}
        <TextInput
          label="URL"
          type="url"
          required
          placeholder="https://example.com/article"
          value={url}
          onChange={(e) => setUrl(e.currentTarget.value)}
        />
        <TextInput
          label="Title"
          placeholder="Optional — extracted automatically"
          value={title}
          onChange={(e) => setTitle(e.currentTarget.value)}
        />
        <TagsInput
          label="Tags"
          placeholder="Add tags..."
          value={tags}
          onChange={setTags}
        />
        <Button type="submit">Save Bookmark</Button>
      </Stack>
    </form>
  )
}

function NoteTab() {
  const navigate = useNavigate()
  const [title, setTitle] = useState('')
  const [content, setContent] = useState('')
  const [tags, setTags] = useState<string[]>([])
  const [error, setError] = useState<string | null>(null)
  const [, executeMutation] = useMutation(CaptureNoteMutation)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)

    const result = await executeMutation({
      input: { title: title || undefined, content, tags: tags.length > 0 ? tags : undefined },
    })
    if (result.error) {
      setError(result.error.graphQLErrors[0]?.message ?? 'Capture failed')
      return
    }

    navigate('/')
  }

  return (
    <form onSubmit={handleSubmit}>
      <Stack gap="md">
        {error && (
          <Alert color="red" variant="light">
            {error}
          </Alert>
        )}
        <TextInput
          label="Title"
          placeholder="Optional"
          value={title}
          onChange={(e) => setTitle(e.currentTarget.value)}
        />
        <Textarea
          label="Content"
          required
          placeholder="Write your note..."
          minRows={4}
          autosize
          value={content}
          onChange={(e) => setContent(e.currentTarget.value)}
        />
        <TagsInput
          label="Tags"
          placeholder="Add tags..."
          value={tags}
          onChange={setTags}
        />
        <Button type="submit">Save Note</Button>
      </Stack>
    </form>
  )
}

function formatDuration(seconds: number): string {
  const m = Math.floor(seconds / 60)
    .toString()
    .padStart(2, '0')
  const s = (seconds % 60).toString().padStart(2, '0')
  return `${m}:${s}`
}

function VoiceTab() {
  const navigate = useNavigate()
  const recorder = useAudioRecorder()
  const [title, setTitle] = useState('')
  const [tags, setTags] = useState<string[]>([])
  const [error, setError] = useState<string | null>(null)
  const [uploading, setUploading] = useState(false)
  const [, executeMutation] = useMutation(CaptureVoiceNoteMutation)

  const audioUrl = useMemo(() => {
    if (recorder.audioBlob) return URL.createObjectURL(recorder.audioBlob)
    return null
  }, [recorder.audioBlob])

  async function handleSave(e: React.FormEvent) {
    e.preventDefault()
    if (!recorder.audioBlob) return

    setError(null)
    setUploading(true)
    try {
      const upload = await uploadAudio(recorder.audioBlob)
      const result = await executeMutation({
        input: {
          audioKey: upload.key,
          title: title || undefined,
          tags: tags.length > 0 ? tags : undefined,
          source: 'web',
        },
      })
      if (result.error) {
        setError(result.error.graphQLErrors[0]?.message ?? 'Save failed')
        return
      }
      navigate('/')
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Upload failed')
    } finally {
      setUploading(false)
    }
  }

  const displayError = error || recorder.error

  return (
    <form onSubmit={handleSave}>
      <Stack gap="md">
        {displayError && (
          <Alert color="red" variant="light">
            {displayError}
          </Alert>
        )}

        <Box
          p="xl"
          style={{
            border: '1px solid var(--mantine-color-gray-3)',
            borderRadius: 'var(--mantine-radius-md)',
            textAlign: 'center',
          }}
        >
          {recorder.status === 'idle' && (
            <Stack align="center" gap="sm">
              <ActionIcon
                size="xl"
                radius="xl"
                color="red"
                variant="filled"
                onClick={recorder.start}
                aria-label="Start recording"
              >
                <Mic size={24} />
              </ActionIcon>
              <Text size="sm" c="dimmed">
                Tap to record
              </Text>
            </Stack>
          )}

          {(recorder.status === 'recording' || recorder.status === 'paused') && (
            <Stack align="center" gap="sm">
              <Group gap="xs" justify="center">
                <Box
                  className={recorder.status === 'recording' ? classes.pulse : undefined}
                  style={{
                    width: 12,
                    height: 12,
                    borderRadius: '50%',
                    backgroundColor: 'var(--mantine-color-red-6)',
                  }}
                />
                <Text fw={600} fz="lg" data-testid="duration">
                  {formatDuration(recorder.duration)}
                </Text>
              </Group>
              <Text size="sm" c="dimmed">
                {recorder.status === 'recording' ? 'Recording...' : 'Paused'}
              </Text>
              <ActionIcon
                size="xl"
                radius="xl"
                color="gray"
                variant="filled"
                onClick={recorder.stop}
                aria-label="Stop recording"
              >
                <Square size={20} />
              </ActionIcon>
            </Stack>
          )}

          {recorder.status === 'stopped' && audioUrl && (
            <Stack align="center" gap="sm">
              {/* eslint-disable-next-line jsx-a11y/media-has-caption */}
              <audio controls src={audioUrl} style={{ width: '100%', maxWidth: 400 }} />
              <Group gap="xs">
                <Text size="sm" c="dimmed">
                  {formatDuration(recorder.duration)}
                </Text>
                <Button variant="subtle" size="xs" onClick={recorder.reset}>
                  Re-record
                </Button>
              </Group>
            </Stack>
          )}
        </Box>

        {recorder.status === 'stopped' && (
          <>
            <TextInput
              label="Title"
              placeholder="Optional"
              value={title}
              onChange={(e) => setTitle(e.currentTarget.value)}
            />
            <TagsInput
              label="Tags"
              placeholder="Add tags..."
              value={tags}
              onChange={setTags}
            />
            <Button type="submit" loading={uploading}>
              Save Voice Note
            </Button>
          </>
        )}
      </Stack>
    </form>
  )
}

export function Capture() {
  return (
    <Container size="sm" py="xl">
      <Stack gap="lg">
        <Title order={2}>Capture</Title>

        <Tabs defaultValue="bookmark">
          <Tabs.List>
            <Tabs.Tab value="bookmark" leftSection={<BookmarkPlus size={16} />}>
              Bookmark
            </Tabs.Tab>
            <Tabs.Tab value="note" leftSection={<FileText size={16} />}>
              Note
            </Tabs.Tab>
            <Tabs.Tab value="voice" leftSection={<Mic size={16} />}>
              Voice
            </Tabs.Tab>
          </Tabs.List>

          <Tabs.Panel value="bookmark" pt="md">
            <BookmarkTab />
          </Tabs.Panel>

          <Tabs.Panel value="note" pt="md">
            <NoteTab />
          </Tabs.Panel>

          <Tabs.Panel value="voice" pt="md">
            <VoiceTab />
          </Tabs.Panel>
        </Tabs>
      </Stack>
    </Container>
  )
}

